    resourceId: "qinq1",
    bridge: "vmbr0",
    serviceVlan: 100,
    serviceVlanProtocol: "802.1ad",
    mtu: 1496,
    dns: "1.1.1.1",
    dnsZone: "example.com",
    ipam: "pve",
    reverseDns: "1.1.1.1",
});
